// ─── Auth_Validator: POST /tasks ─────────────────────────────────────────
// Decodifica o Bearer Token JWT da Cognito e extrai o 'sub' como uid.
const authHeader = $input.item.json.headers?.authorization || "";

if (!authHeader.startsWith("Bearer ")) {
  return [{ json: { error: "Unauthorized", message: "Token ausente ou inválido." } }];
}

const token = authHeader.replace("Bearer ", "").trim();

try {
  const payloadBase64 = token.split(".")[1];
  const payloadJson = Buffer.from(payloadBase64, "base64").toString("utf-8");
  const payload = JSON.parse(payloadJson);

  const uid = payload.sub;
  if (!uid) throw new Error("sub não encontrado no token");

  return [{ json: { ...($input.item.json), uid } }];
} catch (e) {
  return [{ json: { error: "Token inválido", message: e.message } }];
}

