// ─── Tasks-json_builder ──────────────────────────────────────────────────
// userId agora vem do Auth_Validator_POST (sub do JWT Cognito), não mais fixo.
const uid = $('Auth_Validator_POST').first().json.uid;
const aiText = $input.first().json.output || $input.first().json.text || $input.first().json.response?.generations?.[0]?.[0]?.text;

try {
    const jsonMatch = aiText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
        const data = JSON.parse(jsonMatch[0]);
        return [{
            json: {
                userId: uid,
                title: data.title || "Nova Tarefa",
                contexto: data.contexto || "Pessoal",
                tag: data.tag || "Geral",
                categoria: data.categoria || "Tarefa",
                prioridade: data.prioridade || "media",
                nivel_energia: data.nivel_energia || "media",
                duracao_estimada_minutos: data.duracao_estimada_minutos || 15,
                status: "todo",
                notas: data.notas || aiText
            }
        }];
    }
} catch (e) {
    return [{ json: { error: "Erro no mapeamento TDAH", details: e.message } }];
}

